Class ProductSearch Extends %RegisteredObject
{
    /// Search products by category
    ClassMethod SearchProducts(category As %String) As %ListOfDataTypes
    {
        Set results = ##class(%ListOfDataTypes).%New()

        // Simulated product data
        Set products(1) = "Electronics:Laptop"
        Set products(2) = "Electronics:Phone"
        Set products(3) = "Furniture:Chair"
        Set products(4) = "Furniture:Desk"

        // BUGGY: Category filter variable not used in comparison
        Set key = ""
        For {
            Set key = $ORDER(products(key))
            Quit:key=""
            Set product = products(key)
            // Bug: comparing to literal "category" string instead of variable
            If ($PIECE(product, ":", 1) = "category") {
                Do results.Insert($PIECE(product, ":", 2))
            }
        }

        Quit results
    }
}

