Class TestProductSearch Extends %RegisteredObject
{
    ClassMethod TestSearchProducts()
    {
        // Search for Electronics
        Set results = ##class(ProductSearch).SearchProducts("Electronics")
        If (results.Count() '= 2) {
            Throw ##class(%Exception.General).%New("Electronics should have 2 products, got "_results.Count())
        }

        // Search for Furniture
        Set results = ##class(ProductSearch).SearchProducts("Furniture")
        If (results.Count() '= 2) {
            Throw ##class(%Exception.General).%New("Furniture should have 2 products, got "_results.Count())
        }

        // Search for non-existent category
        Set results = ##class(ProductSearch).SearchProducts("Books")
        If (results.Count() '= 0) {
            Throw ##class(%Exception.General).%New("Books should have 0 products, got "_results.Count())
        }
    }
}
